+
+/// Resolve the data directory path without creating it.
+fn resolve_data_dir() -> Result<PathBuf, String> {
+    // 1. Environment variable override
+    if let Ok(dir) = std::env::var("HELMOR_DATA_DIR") {
+        return Ok(PathBuf::from(dir));
+    }
