+            "worktree",
+            "remove",
+            "--force",
+            workspace_dir_arg.as_str(),
+        ],
+        None,
+    );
+    let _ = fs::remove_dir_all(workspace_dir);
+
+    if staged_archive_dir.exists() && !archived_context_dir.exists() {
+        let _ = fs::rename(staged_archive_dir, archived_context_dir);
